# Utility functions for file read/write with pipe-delimited format

def read_users():
    users = {}
    if not os.path.exists(USERS_FILE):
        return users
    with open(USERS_FILE, 'r', encoding='utf-8') as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            username, email, phone, address = line.split('|')
            users[username] = {
                'username': username,
                'email': email,
                'phone': phone,
                'address': address
            }
    return users

def write_users(users):
    with open(USERS_FILE, 'w', encoding='utf-8') as f:
        for u in users.values():
            f.write('|'.join([u['username'], u['email'], u['phone'], u['address']]) + '\n')


def read_books():
    books = {}
    if not os.path.exists(BOOKS_FILE):
        return books
    with open(BOOKS_FILE, 'r', encoding='utf-8') as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) != 10:
                continue
            book_id = int(parts[0])
            title = parts[1]
            author = parts[2]
            isbn = parts[3]
            genre = parts[4]
            publisher = parts[5]
            year = int(parts[6])
            description = parts[7]
            status = parts[8]
            try:
                avg_rating = float(parts[9])
            except ValueError:
                avg_rating = 0.0

            books[book_id] = {
                'book_id': book_id,
                'title': title,
                'author': author,
                'isbn': isbn,
                'genre': genre,
                'publisher': publisher,
                'year': year,
                'description': description,
                'status': status,
                'avg_rating': avg_rating
            }
    return books


def write_books(books):
    with open(BOOKS_FILE, 'w', encoding='utf-8') as f:
        for b in books.values():
            line = '|'.join([
                str(b['book_id']), b['title'], b['author'], b['isbn'], b['genre'], b['publisher'],
                str(b['year']), b['description'], b['status'], str(b['avg_rating'])
