from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Utility functions to read and write data files based on schemas

def parse_books():
    books_path = os.path.join(DATA_DIR, 'books.txt')
    books = []
    if os.path.exists(books_path):
        with open(books_path, 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 8:
                    continue
                book = {
                    'book_id': int(parts[0]),
                    'title': parts[1],
                    'author': parts[2],
                    'isbn': parts[3],
                    'category': parts[4],
                    'price': float(parts[5]),
                    'stock': int(parts[6]),
                    'description': parts[7]
                }
                books.append(book)
    return books


def parse_categories():
    categories_path = os.path.join(DATA_DIR, 'categories.txt')
    categories = []
    if os.path.exists(categories_path):
        with open(categories_path, 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 3:
                    continue
                category = {
                    'category_id': int(parts[0]),
                    'category_name': parts[1],
                    'description': parts[2]
                }
                categories.append(category)
    return categories


def parse_cart():
    cart_path = os.path.join(DATA_DIR, 'cart.txt')
    cart = []
    if os.path.exists(cart_path):
        with open(cart_path, 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 4:
                    continue
                item = {
                    'cart_id': int(parts[0]),
                    'book_id': int(parts[1]),
                    'quantity': int(parts[2]),
                    'added_date': parts[3]
                }
                cart.append(item)
    return cart


def write_cart(cart):
    cart_path = os.path.join(DATA_DIR, 'cart.txt')
    try:
        with open(cart_path, 'w', encoding='utf-8') as f:
            for item in cart:
                line = f"{item['cart_id']}|{item['book_id']}|{item['quantity']}|{item['added_date']}\n"
                f.write(line)
        return True
    except Exception:
        return False


def parse_orders():
    orders_path = os.path.join(DATA_DIR, 'orders.txt')
    orders = []
    if os.path.exists(orders_path):
        with open(orders_path, 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 6:
                    continue
                order = {
                    'order_id': int(parts[0]),
                    'customer_name': parts[1],
                    'order_date': parts[2],
                    'total_amount': float(parts[3]),
                    'status': parts[4],
                    'shipping_address': parts[5]
                }
                orders.append(order)
    return orders


def write_orders(orders):
    orders_path = os.path.join(DATA_DIR, 'orders.txt')
    try:
        with open(orders_path, 'w', encoding='utf-8') as f:
            for order in orders:
                line = f"{order['order_id']}|{order['customer_name']}|{order['order_date']}|{order['total_amount']}|{order['status']}|{order['shipping_address']}\n"
                f.write(line)
        return True
    except Exception:
        return False


def parse_order_items():
    order_items_path = os.path.join(DATA_DIR, 'order_items.txt')
    order_items = []
    if os.path.exists(order_items_path):
        with open(order_items_path, 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 5:
                    continue
                item = {
                    'order_item_id': int(parts[0]),
                    'order_id': int(parts[1]),
                    'book_id': int(parts[2]),
                    'quantity': int(parts[3]),
                    'price': float(parts[4])
                }
                order_items.append(item)
    return order_items


def write_order_items(order_items):
    order_items_path = os.path.join(DATA_DIR, 'order_items.txt')
    try:
        with open(order_items_path, 'w', encoding='utf-8') as f:
            for item in order_items:
                line = f"{item['order_item_id']}|{item['order_id']}|{item['book_id']}|{item['quantity']}|{item['price']}\n"
                f.write(line)
        return True
    except Exception:
        return False


def parse_reviews():
    reviews_path = os.path.join(DATA_DIR, 'reviews.txt')
    reviews = []
    if os.path.exists(reviews_path):
        with open(reviews_path, 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 6:
                    continue
                review = {
                    'review_id': int(parts[0]),
                    'book_id': int(parts[1]),
                    'customer_name': parts[2],
                    'rating': int(parts[3]),
                    'review_text': parts[4],
                    'review_date': parts[5]
                }
                reviews.append(review)
    return reviews


def write_reviews(reviews):
    reviews_path = os.path.join(DATA_DIR, 'reviews.txt')
    try:
        with open(reviews_path, 'w', encoding='utf-8') as f:
            for review in reviews:
                line = f"{review['review_id']}|{review['book_id']}|{review['customer_name']}|{review['rating']}|{review['review_text']}|{review['review_date']}\n"
                f.write(line)
        return True
    except Exception:
        return False


def parse_bestsellers():
    bestsellers_path = os.path.join(DATA_DIR, 'bestsellers.txt')
    bestsellers = []
    if os.path.exists(bestsellers_path):
        with open(bestsellers_path, 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 3:
                    continue
                bs = {
                    'book_id': int(parts[0]),
                    'sales_count': int(parts[1]),
                    'period': parts[2]
                }
                bestsellers.append(bs)
    return bestsellers


