@app.route('/cart', methods=['GET', 'POST'])
def cart():
    cart_data = parse_cart()
    books = parse_books()

    if request.method == 'POST':
        # Process updates
        updated = False
        remove_ids = []
        for item in cart_data:
            item_id = item['cart_id']
            remove_key = f'remove-item-button-{item_id}'
            update_quantity_key = f'update-quantity-{item_id}'

            if remove_key in request.form:
                remove_ids.append(item_id)
                updated = True
            elif update_quantity_key in request.form:
                qty_str = request.form.get(update_quantity_key, '').strip()
                try:
                    qty = int(qty_str)
                    if qty <= 0:
                        remove_ids.append(item_id)
                    else:
                        item['quantity'] = qty
                except Exception:
                    # Invalid qty ignore
                    pass
                updated = True

        if remove_ids:
            cart_data = [item for item in cart_data if item['cart_id'] not in remove_ids]

        if updated:
            write_cart(cart_data)

        return redirect(url_for('cart'))

    # For GET, prepare cart_items and total_amount
    cart_items = []
    total_amount = 0.0

    for item in cart_data:
        book = next((b for b in books if b['book_id'] == item['book_id']), None)
        if not book:
            continue
        price = book['price']
        quantity = item['quantity']
        subtotal = price * quantity
        total_amount += subtotal

        cart_items.append({
            'item_id': item['cart_id'],
            'book_id': book['book_id'],
            'title': book['title'],
            'quantity': quantity,
            'price': price,
            'subtotal': subtotal
        })

    return render_template('cart.html', cart_items=cart_items, total_amount=total_amount)


@app.route('/checkout', methods=['GET', 'POST'])
def checkout():
    cart_data = parse_cart()
    books = parse_books()

    if request.method == 'POST':
        customer_name = request.form.get('customer_name', '').strip()
        shipping_address = request.form.get('shipping_address', '').strip()
        payment_method = request.form.get('payment_method', '').strip()

        # Validate required fields
        if not customer_name or not shipping_address or not payment_method:
            # Possibly render checkout with error (not specified)
            return render_template('checkout.html')

        # Calculate total_amount and prepare order items
        order_items_data = []
        total_amount = 0.0
        for item in cart_data:
            book = next((b for b in books if b['book_id'] == item['book_id']), None)
            if not book:
                continue
            price = book['price']
            quantity = item['quantity']
            subtotal = price * quantity
            total_amount += subtotal
            order_items_data.append({
                'book_id': book['book_id'],
                'quantity': quantity,
                'price': price
            })

        if total_amount <= 0:
            # No valid order
            return render_template('checkout.html')

        # Create new order id
        orders = parse_orders()
        max_order_id = max((o['order_id'] for o in orders), default=0)
        new_order_id = max_order_id + 1
        order_date = datetime.now().strftime('%Y-%m-%d')

        # Append new order
        order_entry = {
            'order_id': new_order_id,
            'customer_name': customer_name,
            'order_date': order_date,
            'total_amount': total_amount,
            'status': 'Pending',
            'shipping_address': shipping_address
        }
        orders.append(order_entry)
        write_orders(orders)

        # Append order items with order_item_id
        order_items = parse_order_items()
        max_order_item_id = max((oi['order_item_id'] for oi in order_items), default=0)

        for i, item in enumerate(order_items_data, start=1):
            max_order_item_id += 1
            oi_entry = {
                'order_item_id': max_order_item_id,
                'order_id': new_order_id,
                'book_id': item['book_id'],
                'quantity': item['quantity'],
                'price': item['price']
            }
            order_items.append(oi_entry)

        write_order_items(order_items)

        # Clear cart
        write_cart([])

        return redirect(url_for('order_history'))

    # GET
    return render_template('checkout.html')


