                    'filename': fields[3],
                    'upload_date': fields[4],
                    'summary': fields[5]
                }
                resumes.append(resume)
    except FileNotFoundError:
        pass
    return resumes


def write_resumes(resumes):
    resumes_path = os.path.join(DATA_DIR, 'resumes.txt')
    with open(resumes_path, 'w', encoding='utf-8') as f:
        for r in resumes:
            line = f"{r['resume_id']}|{r['applicant_name']}|{r['applicant_email']}|{r['filename']}|{r['upload_date']}|{r['summary']}"
            f.write(line + '\n')


def read_job_categories():
    # Not used directly for now, job category is stored in jobs.txt
    path = os.path.join(DATA_DIR, 'job_categories.txt')
    job_categories = []
    try:
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                fields = line.split('|')
                if len(fields) != 3:
                    continue
                mapping = {
                    'mapping_id': int(fields[0]),
                    'job_id': int(fields[1]),
