    upload_date = datetime.datetime.now().strftime('%Y-%m-%d')
    resumes_ids = [r['resume_id'] for r in resumes]
    max_resume_id = max(resumes_ids, default=0)
    new_resume = {
        'resume_id': max_resume_id + 1,
        'applicant_name': '',
        'applicant_email': '',
        'filename': filename,
        'upload_date': upload_date,
        'summary': 'Uploaded resume without details'
    }
    resumes.append(new_resume)
    write_resumes(resumes)

    return redirect(url_for('resume_management'))


@app.route('/resume/<int:resume_id>/delete', methods=['POST'])
def delete_resume(resume_id):
    resumes = read_resumes()
    resume_to_delete = next((r for r in resumes if r['resume_id'] == resume_id), None)
    if not resume_to_delete:
        abort(404)

    # Delete file if exists
    file_path = os.path.join(UPLOAD_FOLDER, resume_to_delete['filename'])
    if os.path.exists(file_path):
        os.remove(file_path)

    resumes = [r for r in resumes if r['resume_id'] != resume_id]
    write_resumes(resumes)

    return redirect(url_for('resume_management'))


@app.route('/search')
def search_results():
    query = request.args.get('query', '').strip()

    jobs = read_jobs()
    companies = read_companies()

    if not query:
        return render_template('search_results.html', query=query, job_results=[], company_results=[])

    query_lower = query.lower()

    # Search jobs by title, company name, location
    company_lookup = {c['company_id']: c for c in companies}

    job_results = []
    for job in jobs:
        company = company_lookup.get(job['company_id'])
        if not company:
            continue
        if (query_lower in job['title'].lower()
            or query_lower in company['company_name'].lower()
            or query_lower in job['location'].lower()):
            job_results.append({
                'job_id': job['job_id'],
                'title': job['title'],
                'company_name': company['company_name'],
                'location': job['location'],
                'salary_min': job['salary_min'],
                'salary_max': job['salary_max'],
                'category': job['category']
            })

    # Search companies by company_name or industry
    company_results = []
    for company in companies:
        if (query_lower in company['company_name'].lower() or query_lower in company['industry'].lower()):
            company_results.append({
                'company_id': company['company_id'],
                'company_name': company['company_name'],
                'industry': company['industry']
            })

    return render_template('search_results.html', query=query, job_results=job_results, company_results=company_results)


if __name__ == '__main__':
    app.run(debug=True)


