                    <td>{{ forecast.high_temp }}</td>
                    <td>{{ forecast.low_temp }}</td>
                    <td>{{ forecast.condition }}</td>
                </tr>
                {% endfor %}
            </tbody>
        </table>
        <button id="back-to-dashboard" onclick="location.href='{{ url_for('dashboard') }}'">Back to Dashboard</button>
    </main>
</body>
</html>
